cwinrt_token wdeblge_gatt_subscribed_client_on_max_notification_size_changed(WDEBLGE_GattSubscribedClient *self, cwinrt_event_fn fn, void *ctx)
{
    IUnknown *handler = NULL;
    cwinrt_event_handle eh = { 0 };
    cwinrt_token tok = { 0 };
    HRESULT hr = cwinrt_event_handler_create(fn, ctx, &handler);
    if (FAILED(hr)) return tok;
    hr = cwinrt_event_subscribe((IUnknown *)self, 8u, 9u, handler, &eh);
    handler->lpVtbl->Release(handler);
    if (FAILED(hr)) return tok;
    return eh.token;
}

void wdeblge_gatt_subscribed_client_off_max_notification_size_changed(WDEBLGE_GattSubscribedClient *self, cwinrt_token token)
{
    cwinrt_event_handle eh = { (IUnknown *)self, 9u, token };
    cwinrt_event_unsubscribe(&eh);
}

